如何使用Go编程语言检测文本中表情符号的情感？您能提供此分析的示例代码吗？
以下是包含表情符号的示例文本：
“我对我的新工作感到😃！💼🎉”
以下是一个可能用于检测表情符号情感的Go代码：
package main
import (
    "fmt"
    "github.com/kyokomi/emoji"
    "github.com/cdipaolo/sentiment"
)
func main() {
    text := “我对我的新工作感到😃！💼🎉”
    positiveWords := []string{“好的”，“快乐的”，“兴奋的”}
    negativeWords := []string{“坏的”，“悲伤的”，“失望的”}
    // 将表情符号转换为文本
    text = emoji.Sprint(text)
    //分析文本情感
    model，err := sentiment.Restore()
    if err != nil {
        panic(err)
    }
    analysis := model.SentimentAnalysis(text，sentiment.English)
    sentimentScore := analysis.Score
    //检测每个表情符号的情感
    for _, e := range emoji.FindAll(text) {
        if sentimentScore > 0 {
            if contains(positiveWords, e.Name) {
                fmt.Printf("表情符号%s具有积极情感。\n"，e.Char)
            } else if contains(negativeWords, e.Name) {
                fmt.Printf("表情符号%s具有消极情感。\n"，e.Char)
            } else {
                fmt.Printf("表情符号%s具有中性情感。\n"，e.Char)
            }
        } else if sentimentScore < 0 {
            if contains(positiveWords, e.Name) {
                fmt.Printf("表情符号%s具有消极情感。\n"，e.Char)
            } else if contains(negativeWords, e.Name) {
                fmt.Printf("表情符号%s具有积极情感。\n"，e.Char)
            } else {
                fmt.Printf("表情符号%s具有中性情感。\n"，e.Char)
            }
        } else {
            fmt.Printf("表情符号%s具有中性情感。\n"，e.Char)
        }
    }
}
func contains(slice []string, element string) bool {
    for _, e := range slice {
        if e == element {
            return true
        }
    }
    return false
}

