#include <iostream>
#include <string>
using namespace std;
int main() {
    string sentence;
    int isMetaphor = 0;
    cout << "Enter a sentence: ";
    getline(cin, sentence);
    if (sentence.find("as") != string::npos) {
        if (sentence.find("as") == sentence.find_last_of("as")) {
            isMetaphor = 1;
        }
    }
    cout << "Output: " << isMetaphor << endl;
    return 0;
}
```

该代码检查句子是否包含单词“as”，如果该单词在句子中仅出现一次，则将其分类为隐喻（isMetaphor = 1），否则将其分类为比喻（isMetaphor = 0）。

