int sub[] = {1, 3};
int sub_size = sizeof(sub) / sizeof(int); // 计算子序列长度

int index = find_subsequence(arr, size, sub, sub_size);

if (index != -1) {
  cout << "The subsequence is found at index " << index << endl;
} else {
  cout << "The subsequence is not found" << endl;
}
